import SwiftUI
import Combine

class TradeViewModel: ObservableObject {
    @Published var stocks: [Stock] = []
    @Published var portfolio: Portfolio = Portfolio()

    private let apiService: APIService = APIService()

    func fetchStocks() {
        apiService.fetchStocks { stocks in
            self.stocks = stocks
        }
    }

    func executeTrade(symbol: String, quantity: Int) {
        if let stock = stocks.first(where: { $0.symbol == symbol }) {
            let trade = Trade(symbol: symbol, quantity: quantity, price: stock.price)
            portfolio.addTrade(trade)
            apiService.executeTrade(trade)
        }
    }
}

struct TradeView: View {
    @ObservedObject var viewModel: TradeViewModel

    var body: some View {
        List {
            ForEach(viewModel.stocks) { stock in
                StockRow(stock: stock, onTradeExecuted: { quantity in
                    viewModel.executeTrade(symbol: stock.symbol, quantity: quantity)
                })
            }
        }
        .onAppear {
            viewModel.fetchStocks()
        }
    }
}

struct StockRow: View {
    let stock: Stock
    let onTradeExecuted: (Int) -> Void

    var body: some View {
        HStack {
            Text(stock.symbol)
            Text(String(stock.price))
            TextField("Quantity", value: .constant(0), formatter: NumberFormatter())
                .keyboardType(.numberPad)
            Button("Buy") {
                onTradeExecuted(Int(textFieldValue))
            }
        }
    }
}

struct Portfolio {
    var trades: [Trade] = []

    func addTrade(_ trade: Trade) {
        trades.append(trade)
    }
}

struct Trade {
    let symbol: String
    let quantity: Int
    let price: Double
}

struct Stock {
    let symbol: String
    let price: Double
}

